package com.restaurantcraft.screen; import com.restaurantcraft.menu.RestaurantManagementMenu; import com.restaurantcraft.network.*; import com.restaurantcraft.registry.ModPackets; import net.minecraft.client.gui.GuiGraphics; import net.minecraft.client.gui.components.Button; import net.minecraft.client.gui.screens.inventory.AbstractContainerScreen; import net.minecraft.network.chat.Component; import net.minecraft.world.entity.player.Inventory; public class RestaurantManagementScreen extends AbstractContainerScreen<RestaurantManagementMenu>{ public RestaurantManagementScreen(RestaurantManagementMenu m, Inventory i, Component t){super(m,i,t);imageWidth=176;imageHeight=222;} protected void init(){super.init(); addRenderableWidget(Button.builder(Component.translatable("button.restaurant_craft.start"),b->ModPackets.sendToServer(new C2SStartBusinessPacket(menu.be.getBlockPos()))).bounds(leftPos+8,topPos+8,48,20).build()); addRenderableWidget(Button.builder(Component.translatable("button.restaurant_craft.upgrade"),b->ModPackets.sendToServer(new C2SUpgradeRestaurantPacket(menu.be.getBlockPos()))).bounds(leftPos+60,topPos+8,48,20).build()); addRenderableWidget(Button.builder(Component.translatable("button.restaurant_craft.detect"),b->ModPackets.sendToServer(new C2SDetectAreaPacket(menu.be.getBlockPos()))).bounds(leftPos+112,topPos+8,56,20).build()); } public void render(GuiGraphics g,int mx,int my,float pt){renderBackground(g);super.render(g,mx,my,pt);renderTooltip(g,mx,my);} protected void renderBg(GuiGraphics g,float p,int mx,int my){g.fill(leftPos,topPos,leftPos+imageWidth,topPos+imageHeight,0xCC202020); var d=menu.be.data; g.drawString(font,Component.literal(d.restaurantName+" "+d.level+"星"),leftPos+8,topPos+122,0xFFFFFF,false); g.drawString(font,Component.literal("人气 "+d.popularity+" / "+menu.be.level().popularityCap+" 额度 "+d.money),leftPos+8,topPos+132,0xFFFFFF,false);} }
